using System.Collections;
using UnityEngine;

/// <summary>
/// Mapa-Múndi (GDD "Câmara"): controla a câmara do Mapa-Múndi de forma
/// totalmente configurável no Inspector — vista geral do Coração de Gaia,
/// aproximação por "trechos" (<see cref="CameraShot"/>) definidos em cada
/// <see cref="WorldMapConnection"/>, foco directo num nó (ex: cutscene de
/// desbloqueio do boss) e o modo livre "Visão do Mapa-Múndi".
///
/// Todo o movimento é feito directamente sobre uma <see cref="Camera"/>
/// ortográfica 2D (posição X/Y + orthographicSize), com blends suaves —
/// não depende de Cinemachine, para permitir o controlo "por trechos"
/// exigido pelo GDD (não apenas distância).
/// </summary>
[RequireComponent(typeof(Camera))]
public class WorldMapCameraRig : MonoBehaviour
{
    [Header("Câmara")]
    [Tooltip("Câmara usada pelo Mapa-Múndi. Se vazio, usa a Camera neste GameObject.")]
    public Camera mapCamera;

    [Header("Coração de Gaia — Vista Geral")]
    [Tooltip("Ponto onde a câmara fica centrada quando o jogador está no Coração de Gaia (vê Gaia e os 6 mundos em simultâneo).")]
    public Transform gaiaHubAnchor;

    [Tooltip("Zoom (tamanho ortográfico) da câmara no Coração de Gaia — bem afastado, para mostrar Gaia e os 6 mundos. Caminhos/áreas internas dos mundos ficam invisíveis a este zoom.")]
    public float gaiaHubOrthographicSize = 12f;

    [Header("Transição Padrão")]
    [Tooltip("Duração (segundos) usada para mudanças de plano que não especificam a sua própria duração (ex: ir para o Coração de Gaia, centrar no nó actual ao abrir o mapa, regresso da Visão do Mapa-Múndi).")]
    [Min(0.01f)]
    public float defaultBlendDuration = 1f;

    [Tooltip("Zoom (tamanho ortográfico) padrão usado para centrar a câmara num nó comum (1-2 áreas em quadro), quando o ramo não define um CameraShot próprio para esse ponto.")]
    public float defaultNodeOrthographicSize = 5f;

    [Header("Visão do Mapa-Múndi (Upgrade)")]
    [Tooltip("Velocidade de deslocação da câmara em modo Visão do Mapa-Múndi (analógico direito), em unidades de mundo por segundo.")]
    public float freeLookPanSpeed = 6f;

    [Tooltip("Zoom (tamanho ortográfico) usado durante a Visão do Mapa-Múndi (mais afastado que o normal, para ver mais do mundo actual).")]
    public float freeLookOrthographicSize = 8f;

    [Tooltip("Distância máxima (unidades de mundo, X e Y) que a câmara se pode afastar da bola durante a Visão do Mapa-Múndi.")]
    public Vector2 freeLookMaxOffset = new Vector2(20f, 12f);

    /// <summary>A câmara está a meio de um blend de posição/zoom.</summary>
    public bool IsBlending { get; private set; }

    /// <summary>A câmara está no modo "Visão do Mapa-Múndi" (analógico direito controla o pan).</summary>
    public bool IsFreeLooking { get; private set; }

    private Coroutine blendRoutine;
    private Vector3 freeLookOffset;
    private Transform freeLookPivot;

    private WorldMapConnection trackedConnection;
    private int trackedShotIndex = -1;

    private void Awake()
    {
        if (mapCamera == null) mapCamera = GetComponent<Camera>();
    }

    // -------------------- Movimentos Directos --------------------

    /// <summary>Move a câmara para "position" com o zoom "orthographicSize", em "duration" segundos (corta qualquer blend em curso).</summary>
    public void MoveTo(Vector3 position, float orthographicSize, float duration)
    {
        if (blendRoutine != null) StopCoroutine(blendRoutine);
        blendRoutine = StartCoroutine(BlendTo(position, orthographicSize, Mathf.Max(0.01f, duration)));
    }

    public void MoveTo(Transform anchor, float orthographicSize, float duration)
    {
        if (anchor == null) return;
        MoveTo(anchor.position, orthographicSize, duration);
    }

    /// <summary>Posiciona a câmara instantaneamente (sem blend) — usado ao abrir o mapa, antes do primeiro fade-in.</summary>
    public void SnapTo(Vector3 position, float orthographicSize)
    {
        if (blendRoutine != null) { StopCoroutine(blendRoutine); blendRoutine = null; }
        IsBlending = false;

        position.z = mapCamera.transform.position.z;
        mapCamera.transform.position = position;
        if (mapCamera.orthographic) mapCamera.orthographicSize = orthographicSize;
    }

    public void SnapTo(Transform anchor, float orthographicSize)
    {
        if (anchor != null) SnapTo(anchor.position, orthographicSize);
    }

    /// <summary>Vista geral do Coração de Gaia (afastada, mostra os 6 mundos; caminhos/áreas internas ficam invisíveis).</summary>
    public void ShowGaiaHub(float duration = -1f)
    {
        IsFreeLooking = false;
        ResetShotTracking();
        Vector3 pos = gaiaHubAnchor != null ? gaiaHubAnchor.position : mapCamera.transform.position;
        MoveTo(pos, gaiaHubOrthographicSize, duration > 0f ? duration : defaultBlendDuration);
    }

    /// <summary>Centra a câmara num nó com um zoom específico — usado ao abrir o mapa sobre o nó actual e na cutscene de desbloqueio do boss.</summary>
    public void FocusNode(WorldMapNode node, float orthographicSize = -1f, float duration = -1f)
    {
        if (node == null) return;

        IsFreeLooking = false;
        ResetShotTracking();
        MoveTo(node.transform.position, orthographicSize > 0f ? orthographicSize : defaultNodeOrthographicSize, duration > 0f ? duration : defaultBlendDuration);
    }

    // -------------------- Trechos ao Longo de um Ramo --------------------

    /// <summary>
    /// Chamado continuamente enquanto a bola percorre "connection" (progress 0-1).
    /// Escolhe o <see cref="CameraShot"/> mais avançado cujo "progress" já foi
    /// atingido e inicia um blend até lá — só um blend por trecho (não reinicia
    /// a cada frame). Se "connection" não tiver nenhum CameraShot, a câmara
    /// segue a bola directamente com o zoom padrão.
    /// </summary>
    public void FollowConnectionProgress(WorldMapConnection connection, float progress)
    {
        if (connection == null) return;

        if (connection != trackedConnection)
        {
            trackedConnection = connection;
            trackedShotIndex = -1;
        }

        if (connection.cameraShots == null || connection.cameraShots.Count == 0)
        {
            // Sem trechos configurados: segue a bola directamente.
            Vector3 pos = connection.GetPositionAtProgress(progress);
            pos.z = mapCamera.transform.position.z;
            mapCamera.transform.position = pos;
            return;
        }

        int best = -1;
        for (int i = 0; i < connection.cameraShots.Count; i++)
            if (connection.cameraShots[i].progress <= progress && (best < 0 || connection.cameraShots[i].progress >= connection.cameraShots[best].progress))
                best = i;

        if (best < 0) best = 0;
        if (best == trackedShotIndex) return;

        trackedShotIndex = best;
        var shot = connection.cameraShots[best];

        Vector3 shotPos = shot.cameraAnchor != null ? shot.cameraAnchor.position : connection.GetPositionAtProgress(shot.progress);
        MoveTo(shotPos, shot.orthographicSize, Mathf.Max(0.01f, shot.blendDuration));
    }

    /// <summary>Repõe o rastreio de trechos — chamar sempre que a bola para num nó ou troca de ramo, para reavaliar os CameraShots desde o início.</summary>
    public void ResetShotTracking()
    {
        trackedConnection = null;
        trackedShotIndex = -1;
    }

    private IEnumerator BlendTo(Vector3 targetPos, float targetSize, float duration)
    {
        IsBlending = true;

        Vector3 startPos = mapCamera.transform.position;
        float startSize = mapCamera.orthographic ? mapCamera.orthographicSize : targetSize;
        targetPos.z = startPos.z;

        float elapsed = 0f;
        while (elapsed < duration)
        {
            elapsed += Time.deltaTime;
            float k = Mathf.SmoothStep(0f, 1f, Mathf.Clamp01(elapsed / duration));

            mapCamera.transform.position = Vector3.Lerp(startPos, targetPos, k);
            if (mapCamera.orthographic) mapCamera.orthographicSize = Mathf.Lerp(startSize, targetSize, k);

            yield return null;
        }

        mapCamera.transform.position = targetPos;
        if (mapCamera.orthographic) mapCamera.orthographicSize = targetSize;

        IsBlending = false;
        blendRoutine = null;
    }

    // -------------------- Visão do Mapa-Múndi (Upgrade) --------------------

    /// <summary>
    /// Entra no modo "Visão do Mapa-Múndi": a câmara passa a ser controlada pelo
    /// analógico direito (<see cref="Pan"/>), afastando-se a partir da posição
    /// da bola (que permanece parada). Não revela outros mundos — apenas o
    /// mundo onde a bola está.
    /// </summary>
    public void EnterFreeLook(Transform ballPivot)
    {
        IsFreeLooking = true;
        freeLookPivot = ballPivot;
        freeLookOffset = Vector3.zero;

        Vector3 pos = ballPivot != null ? ballPivot.position : mapCamera.transform.position;
        MoveTo(pos, freeLookOrthographicSize, defaultBlendDuration);
    }

    /// <summary>Move a câmara em modo Visão do Mapa-Múndi (analógico direito), limitado por <see cref="freeLookMaxOffset"/> em torno da bola.</summary>
    public void Pan(Vector2 input)
    {
        if (!IsFreeLooking || freeLookPivot == null || IsBlending) return;

        freeLookOffset += (Vector3)(input * freeLookPanSpeed * Time.deltaTime);
        freeLookOffset.x = Mathf.Clamp(freeLookOffset.x, -freeLookMaxOffset.x, freeLookMaxOffset.x);
        freeLookOffset.y = Mathf.Clamp(freeLookOffset.y, -freeLookMaxOffset.y, freeLookMaxOffset.y);

        Vector3 target = freeLookPivot.position + freeLookOffset;
        target.z = mapCamera.transform.position.z;
        mapCamera.transform.position = target;
    }

    /// <summary>
    /// Sai do modo Visão do Mapa-Múndi e devolve a câmara suavemente à bola —
    /// chamado quando o jogador move a bola com o analógico esquerdo (GDD:
    /// "mover a bola com o stick esquerdo termina a observação e retorna a
    /// câmara suavemente").
    /// </summary>
    public void ExitFreeLook(Transform ballPivot, float orthographicSize = -1f, float duration = -1f)
    {
        IsFreeLooking = false;
        freeLookOffset = Vector3.zero;

        if (ballPivot != null)
            MoveTo(ballPivot.position, orthographicSize > 0f ? orthographicSize : defaultNodeOrthographicSize, duration > 0f ? duration : defaultBlendDuration);
    }
}
